import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"6.5 小结","description":"","frontmatter":{},"headers":[],"relativePath":"06/5.md","filePath":"06/5.md","lastUpdated":null}'),t={name:"06/5.md"};function n(l,s,r,_,d,c){return a(),i("div",null,[...s[0]||(s[0]=[o('<h1 id="_6-5-小结" tabindex="-1">6.5 小结 <a class="header-anchor" href="#_6-5-小结" aria-label="Permalink to &quot;6.5 小结&quot;">​</a></h1><p>这章我们学习了什么是session，什么是cookie，以及他们两者之间的关系。但是目前Go官方标准包里面不支持session，所以我们设计了一个session管理器，实现了session从创建到销毁的整个过程。然后定义了Provider的接口，使得可以支持各种后端的session存储，然后我们在第三小节里面介绍了如何使用内存存储来实现session的管理。第四小节我们讲解了session劫持的过程，以及我们如何有效的来防止session劫持。通过这一章的讲解，希望能够让读者了解整个sesison的执行原理以及如何实现，而且是如何更加安全的使用session。</p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一节: <a href="/06/4.html">session存储</a></li><li>下一章: <a href="/07/0.html">文本处理</a></li></ul>',4)])])}const f=e(t,[["render",n]]);export{p as __pageData,f as default};
